const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();

const PORT = process.env.PORT || 3000;
const SESSION_SECRET = process.env.SESSION_SECRET || 'change-this-session-secret';
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || '';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || '';
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER || '';

const twilioClient =
  TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN
    ? twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
    : null;

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

app.use(
  session({
    secret: SESSION_SECRET,
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: false,
      sameSite: 'lax',
      maxAge: 10 * 60 * 1000
    }
  })
);

function generateSixDigitCode() {
  return crypto.randomInt(100000, 1000000).toString();
}

async function sendSms(to, body) {
  if (!twilioClient) {
    console.log(`[DEV SMS] To: ${to} | Message: ${body}`);
    return { sid: 'mock-message-sid' };
  }

  return twilioClient.messages.create({
    body,
    from: TWILIO_PHONE_NUMBER,
    to
  });
}

function ensureSession(req, res, next) {
  if (!req.session) {
    return res.status(500).json({ error: 'Session unavailable' });
  }
  next();
}

app.post('/2fa/send', ensureSession, async (req, res) => {
  try {
    const { phoneNumber } = req.body;

    if (!phoneNumber || typeof phoneNumber !== 'string') {
      return res.status(400).json({ error: 'Valid phoneNumber is required' });
    }

    const code = generateSixDigitCode();
    const expiresAt = Date.now() + 5 * 60 * 1000;

    req.session.twoFactor = {
      phoneNumber,
      code,
      expiresAt,
      verified: false,
      attempts: 0
    };

    await sendSms(phoneNumber, `Your verification code is: ${code}`);

    return res.json({
      message: 'Verification code sent'
    });
  } catch (error) {
    return res.status(500).json({
      error: 'Failed to send verification code'
    });
  }
});

app.post('/2fa/verify', ensureSession, (req, res) => {
  const { code } = req.body;
  const twoFactor = req.session.twoFactor;

  if (!twoFactor) {
    return res.status(400).json({ error: 'No verification code requested' });
  }

  if (twoFactor.verified) {
    return res.json({ message: 'Already verified' });
  }

  if (Date.now() > twoFactor.expiresAt) {
    req.session.twoFactor = null;
    return res.status(400).json({ error: 'Verification code expired' });
  }

  twoFactor.attempts += 1;

  if (twoFactor.attempts > 5) {
    req.session.twoFactor = null;
    return res.status(429).json({ error: 'Too many failed attempts' });
  }

  if (!code || typeof code !== 'string') {
    return res.status(400).json({ error: 'Code is required' });
  }

  if (code !== twoFactor.code) {
    return res.status(401).json({ error: 'Invalid verification code' });
  }

  twoFactor.verified = true;
  req.session.isTwoFactorAuthenticated = true;

  return res.json({
    message: 'Two-factor authentication successful'
  });
});

app.get('/2fa/status', ensureSession, (req, res) => {
  return res.json({
    twoFactorAuthenticated: !!req.session.isTwoFactorAuthenticated,
    hasPendingChallenge: !!req.session.twoFactor && !req.session.twoFactor.verified
  });
});

app.post('/logout', ensureSession, (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).json({ error: 'Failed to logout' });
    }
    return res.json({ message: 'Logged out' });
  });
});

app.get('/protected', ensureSession, (req, res) => {
  if (!req.session.isTwoFactorAuthenticated) {
    return res.status(403).json({ error: '2FA required' });
  }

  return res.json({
    message: 'Access granted to protected resource'
  });
});

app.listen(PORT, () => {
  console.log(`2FA app listening on port ${PORT}`);
});